const inSearch = $('YW: In Search').first().json;
const events = $('YW: Events').first().json;
const crawl = $('YW: Crawl').first().json;
const queries = $('YW: Queries').first().json;

const history = inSearch.history || [];
const latest = history[history.length - 1];
const weekAgo = history.length >= 8 ? history[history.length - 8] : history[0];
const monthAgo = history.length >= 30 ? history[history.length - 30] : history[0];
const pagesCurrent = latest.value;
const pagesWeekDelta = latest.value - weekAgo.value;
const pagesWeekPct = weekAgo.value > 0 ? (100 * pagesWeekDelta / weekAgo.value).toFixed(1) : '0';
const pagesMonthPct = monthAgo.value > 0 ? (100*(latest.value - monthAgo.value)/monthAgo.value).toFixed(1) : '0';

const inds = events.indicators || {};
const app = inds.APPEARED_IN_SEARCH || [];
const rem = inds.REMOVED_FROM_SEARCH || [];
const app7 = app.slice(-7).reduce((s,p)=>s+p.value, 0);
const rem7 = rem.slice(-7).reduce((s,p)=>s+p.value, 0);
const net7 = app7 - rem7;

const cInds = crawl.indicators || {};
const http200 = [];
for (const k in cInds) { if (k.indexOf('HTTP_2XX') >= 0) http200.push(...cInds[k]); }
const crawl7 = http200.slice(-7).reduce((s,p)=>s+p.value, 0);

const qRows = queries.queries || [];
const totalClicks = qRows.reduce((s,q)=>s+(q.indicators.TOTAL_CLICKS||0), 0);
const totalShows = qRows.reduce((s,q)=>s+(q.indicators.TOTAL_SHOWS||0), 0);
const ctr = totalShows > 0 ? (100*totalClicks/totalShows).toFixed(2) : '0';

// Top-5 queries
let topQueries = '';
for (let i=0; i<Math.min(5, qRows.length); i++) {
  const q = qRows[i];
  const qt = q.query_text || '?';
  const cl = Math.round(q.indicators.TOTAL_CLICKS || 0);
  const sh = Math.round(q.indicators.TOTAL_SHOWS || 0);
  const pos = (q.indicators.AVG_SHOW_POSITION || 0).toFixed(1);
  topQueries += `• ${qt}: ${cl} кл / ${sh} пок, поз ${pos}\n`;
}

const today = new Date().toISOString().slice(0,10);

let msg = `📊 *SEO Недельный аудит Яндекса* \\· ${today}\n\n`;
msg += `*1. Страниц в индексе:* ${pagesCurrent.toLocaleString('ru-RU')}\n`;
msg += `   неделя: ${pagesWeekDelta>=0?'+':''}${pagesWeekDelta.toLocaleString('ru-RU')} (${pagesWeekPct}%)\n`;
msg += `   месяц: ${pagesMonthPct}%\n`;
msg += `   Цель: 55 000+ (вернуть февральский пик)\n\n`;

msg += `*2. APPEARED/REMOVED (7 дн):*\n`;
msg += `   Появилось: ${app7.toLocaleString('ru-RU')}\n`;
msg += `   Удалено:   ${rem7.toLocaleString('ru-RU')}\n`;
msg += `   Net:       ${net7>=0?'+':''}${net7.toLocaleString('ru-RU')}\n`;
msg += `   Цель: стабильный плюс\n\n`;

msg += `*3. Обход краулером 200 OK (7 дн):* ${crawl7.toLocaleString('ru-RU')}\n`;
msg += `   Среднее/день: ${Math.round(crawl7/7)}\n`;
msg += `   Цель: 500+/день стабильно\n\n`;

msg += `*4. Показы (impressions, 7 дн):* ${totalShows.toLocaleString('ru-RU')}\n`;
msg += `   Среднее/день: ${Math.round(totalShows/7)}\n`;
msg += `   Цель: 1 000+/день\n\n`;

msg += `*5. Клики из поиска (7 дн):* ${totalClicks}\n`;
msg += `   Среднее/день: ${(totalClicks/7).toFixed(1)}\n`;
msg += `   Цель: 100+/день\n\n`;

msg += `*6. CTR:* ${ctr}%\n`;
msg += `   Цель: 5-10%\n\n`;

msg += `*7. Конверсии SEO-трафика:* требуется GA4 audit\n\n`;

msg += `🔎 *Топ-5 запросов:*\n${topQueries}`;

return [{json:{chat_id: '83436260', text: msg, parse_mode: 'Markdown'}}];

